def adapt(a_payload):
    from decimal import Decimal, ROUND_HALF_UP

    raw = a_payload.get("amount", 0)

    # Normalize the incoming value to a Decimal without assuming its scale/type.
    if raw is None:
        raw = 0

    if isinstance(raw, bool):
        # Avoid treating booleans as integers silently; coerce to 0/1 amount.
        value = Decimal(int(raw))
    elif isinstance(raw, int):
        value = Decimal(raw)
    elif isinstance(raw, float):
        # Use repr via str to preserve the intended human-readable value.
        value = Decimal(str(raw))
    elif isinstance(raw, str):
        s = raw.strip()
        if s == "":
            value = Decimal(0)
        else:
            # Strip common currency symbols/whitespace; keep sign, digits, separators.
            cleaned = s.replace("\u20ac", "").replace("EUR", "").replace("eur", "")
            cleaned = cleaned.replace(" ", "").replace("_", "")

            # Decide decimal separator between '.' and ','.
            if "." in cleaned and "," in cleaned:
                # The last-occurring separator is the decimal point.
                if cleaned.rfind(",") > cleaned.rfind("."):
                    cleaned = cleaned.replace(".", "").replace(",", ".")
                else:
                    cleaned = cleaned.replace(",", "")
            elif "," in cleaned:
                # Comma could be decimal (e.g. "12,50") or thousands ("1,234").
                parts = cleaned.split(",")
                if len(parts) == 2 and len(parts[1]) != 3:
                    cleaned = cleaned.replace(",", ".")
                else:
                    cleaned = cleaned.replace(",", "")
            try:
                value = Decimal(cleaned)
            except Exception:
                value = Decimal(0)
    else:
        try:
            value = Decimal(str(raw))
        except Exception:
            value = Decimal(0)

    quantized = value.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

    return {"total": float(quantized)}

