    from decimal import Decimal, ROUND_HALF_UP

    raw = a_payload.get("amount", 0)

    # Normalize the raw value into a Decimal, tolerating common encodings.
    if raw is None:
        dec = Decimal("0")
    elif isinstance(raw, bool):
        # Guard against bool being treated as int.
        dec = Decimal("0")
    elif isinstance(raw, int):
