        # (cents). Since the sample value is 0 we cannot disambiguate.
        # The safest, most common convention for monetary integer fields is
        # minor units (cents), so we scale by 100.
        dec = Decimal(raw) / Decimal(100)
    elif isinstance(raw, float):
        # A float already implies a fractional currency amount in major units.
        dec = Decimal(str(raw))
    elif isinstance(raw, str):
        s = raw.strip()
        if s == "":
