def adapt(a_payload):
    # We require {"state": str} with one of "active", "pending", "closed".
    # System A gives {"status": <value>}. We do NOT know their exact convention,
    # so we defensively handle common encodings (strings and numeric codes),
    # and fail safe to "pending" (a non-destructive, neutral middle state)
    # when the value is unrecognized.

    _VALID = {"active", "pending", "closed"}

    def _normalize(raw):
        # Direct string matches (case-insensitive, trimmed).
        if isinstance(raw, str):
            s = raw.strip().lower()
            if s in _VALID:
                return s
            # Common synonyms/aliases mapped to our vocabulary.
            aliases = {
                "open": "active",
                "opened": "active",
                "enabled": "active",
                "on": "active",
                "live": "active",
                "true": "active",
                "waiting": "pending",
                "hold": "pending",
                "in_progress": "pending",
                "processing": "pending",
                "new": "pending",
                "closed": "closed",
                "close": "closed",
                "done": "closed",
                "complete": "closed",
                "completed": "closed",
                "finished": "closed",
                "inactive": "closed",
                "disabled": "closed",
                "off": "closed",
                "false": "closed",
                "resolved": "closed",
            }
            if s in aliases:
                return aliases[s]
            # Numeric-looking strings.
            try:
                return _from_int(int(s))
            except (ValueError, TypeError):
                return None
        # Boolean handling (before int, since bool is a subclass of int).
        if isinstance(raw, bool):
            return "active" if raw else "closed"
        if isinstance(raw, int):
            return _from_int(raw)
        return None

    def _from_int(n):
        # Best-guess numeric convention. The sample used status=1.
        # We assume a common ordering where 1 is the primary/active state.
        mapping = {
            0: "pending",
            1: "active",
            2: "closed",
        }
        return mapping.get(n)

    raw = a_payload.get("status") if isinstance(a_payload, dict) else None
    state = _normalize(raw)
    if state not in _VALID:
        state = "pending"  # safe, neutral fallback
    return {"state": state}

