            token = value.strip().lower()
            if token in active_tokens:
                return "active"
            if token in pending_tokens:
                return "pending"
            if token in closed_tokens:
                return "closed"

        # Unknown / missing: safest neutral default.
        return "pending"

    return {"state": normalize(status)}

